## Parallel Batch Processing: 6 Hours → 30 Minutes

### Step 1 — Identify the Bottleneck

```bash
# Before: single-threaded job profile
Total records:      10,000,000
Per record time:    2.16ms (DB read + score compute + DB write)
Single-threaded:    10M × 2.16ms = 6 hours

# With 32 parallel threads:
10M ÷ 32 × 2.16ms = 11.25 minutes  ← theoretical
# Accounting for DB contention and I/O: ~25-30 minutes realistic
```

### Step 2 — Chunk-Based Fan-Out with Spring Batch

```java
@Configuration
@EnableBatchProcessing
public class UserScoringBatchConfig {

    @Bean
    public Job userScoringJob(JobBuilderFactory jobs, Step scoringStep) {
        return jobs.get("userScoringJob")
            .start(scoringStep)
            .build();
    }

    @Bean
    public Step scoringStep(StepBuilderFactory steps,
                             ItemReader<UserRecord> reader,
                             ItemProcessor<UserRecord, UserScore> processor,
                             ItemWriter<UserScore> writer) {
        return steps.get("scoringStep")
            .<UserRecord, UserScore>chunk(1000)        // read 1000 records per chunk
            .reader(reader)
            .processor(processor)
            .writer(writer)
            .taskExecutor(batchTaskExecutor())         // parallel chunk processing
            .throttleLimit(32)                         // 32 concurrent chunks
            .build();
    }

    @Bean
    public TaskExecutor batchTaskExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(32);
        executor.setMaxPoolSize(32);
        executor.setThreadNamePrefix("batch-worker-");
        executor.initialize();
        return executor;
    }

    @Bean
    @StepScope
    public JpaPagingItemReader<UserRecord> reader(EntityManagerFactory emf) {
        JpaPagingItemReader<UserRecord> reader = new JpaPagingItemReader<>();
        reader.setEntityManagerFactory(emf);
        reader.setQueryString("SELECT u FROM UserRecord u ORDER BY u.id");
        reader.setPageSize(1000);  // bulk-fetch 1000 at a time — no N+1
        return reader;
    }
}
```

### Step 3 — Parallel Processing per Chunk

```java
@Component
public class UserScoreProcessor implements ItemProcessor<UserRecord, UserScore> {

    // Stateless — safe for parallel use by 32 threads
    @Override
    public UserScore process(UserRecord user) {
        double score = scoreEngine.compute(
            user.getPurchaseHistory(),
            user.getBrowsingSignals(),
            user.getSegment()
        );
        return new UserScore(user.getId(), score, LocalDateTime.now());
    }
}

@Component
public class UserScoreBulkWriter implements ItemWriter<UserScore> {

    @Override
    public void write(List<? extends UserScore> scores) {
        // Single bulk INSERT for entire chunk — much faster than row-by-row
        jdbcTemplate.batchUpdate(
            "INSERT INTO user_scores (user_id, score, computed_at) VALUES (?, ?, ?) "
          + "ON CONFLICT (user_id) DO UPDATE SET score=EXCLUDED.score, computed_at=EXCLUDED.computed_at",
            scores,
            scores.size(),
            (ps, score) -> {
                ps.setString(1, score.userId());
                ps.setDouble(2, score.score());
                ps.setTimestamp(3, Timestamp.valueOf(score.computedAt()));
            }
        );
    }
}
```

### Step 4 — Progress Monitoring

```java
@Component
public class BatchProgressListener implements ChunkListener {
    private final AtomicLong processedCount = new AtomicLong(0);
    private final long totalCount = 10_000_000L;
    private final long startTime = System.currentTimeMillis();

    @Override
    public void afterChunk(ChunkContext context) {
        long done = processedCount.addAndGet(1000);
        if (done % 100_000 == 0) {  // log every 100k records
            long elapsed = System.currentTimeMillis() - startTime;
            double rate = (double) done / elapsed * 1000;   // records/sec
            long etaSeconds = (long) ((totalCount - done) / rate);
            log.info("Progress: {}/{} ({:.1f}%) | Rate: {:.0f} rec/s | ETA: {}s",
                done, totalCount, (done * 100.0 / totalCount), rate, etaSeconds);
        }
    }
}
```

### Observed Output

```
2025-01-15 01:00:00 - Batch job started. Total: 10,000,000 records
2025-01-15 01:03:20 - Progress: 1,000,000/10,000,000 (10.0%) | Rate: 5,050 rec/s | ETA: 1782s
2025-01-15 01:13:00 - Progress: 5,000,000/10,000,000 (50.0%) | Rate: 5,120 rec/s | ETA: 977s
2025-01-15 01:27:45 - Progress: 10,000,000/10,000,000 (100.0%) | Rate: 5,085 rec/s
2025-01-15 01:27:45 - Batch job completed in 27m 45s  ✅
```

